// /frontend/src/components/Hourly.jsx
import React, { useMemo, useRef, useState } from "react";

export default function Hourly({ hourly = [], timezone = "local" }) {
  const listRef = useRef(null);
  const [page, setPage] = useState(0);
  const items = useMemo(() => hourly.slice(0, 24), [hourly]); // OW has plenty of hours

  const onScroll = () => {
    const el = listRef.current;
    if (!el) return;
    const w = el.clientWidth;
    setPage(Math.round(el.scrollLeft / Math.max(1, w * 0.8)));
  };

  const iconUrl = (code) => `https://openweathermap.org/img/wn/${code}@2x.png`;

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-3">
      <div
        ref={listRef}
        onScroll={onScroll}
        className="flex gap-3 overflow-x-auto snap-x snap-mandatory scrollbar-none"
      >
        {items.map((h, i) => {
          const t = (h?.dt ? new Date(h.dt * 1000) : new Date(Date.now() + i * 3600_000))
            .toLocaleTimeString([], { hour: "numeric" });
          const temp = Math.round(h?.temp ?? 0);
          const icon = h?.weather?.[0]?.icon ?? "01d";
          return (
            <div key={i} className="min-w-[84px] snap-start text-center px-3 py-4 rounded-xl bg-white/5">
              <div className="text-xs opacity-70">{t}</div>
              <img src={iconUrl(icon)} alt="" className="h-8 w-8 mx-auto my-1" />
              <div className="text-2xl">{temp}°</div>
            </div>
          );
        })}
      </div>

      {/* page dots on mobile */}
      <div className="flex justify-center gap-1 mt-3 md:hidden">
        {Array.from({ length: Math.ceil(items.length / 4) }).map((_, i) => (
          <span key={i} className={`h-2 w-2 rounded-full ${i === page ? "bg-purple-400" : "bg-white/30"}`} />
        ))}
      </div>
    </div>
  );
}
